fn red_label_shell_image_byte(address: u16) -> Result<Option<u8>, String> {
    for image in red_label_shell_images()? {
        let Some(offset) = address.checked_sub(image.address) else {
            continue;
        };
        let index = usize::from(offset);
        if index < image.bytes.len() {
            return Ok(Some(image.bytes[index]));
        }
    }
    Ok(None)
}

