fn red_label_object_image_word(
    address: u16,
    picture: &RedLabelObjectPicture,
) -> Result<u16, String> {
    let high = red_label_object_image_byte_required(address, picture)?;
    let low = red_label_object_image_byte_required(address.wrapping_add(1), picture)?;
    Ok(u16::from_be_bytes([high, low]))
}

