fn parse_routine_addresses(text: &'static str) -> Result<Vec<RedLabelRoutineAddress>, String> {
    let mut lines = text.lines();
    match lines.next() {
        Some("label\taddress\tsource") => {}
        _ => {
            return Err(String::from(
                "red-label routine address asset header is invalid",
            ));
        }
    }

    let mut addresses = Vec::new();
    for (line_index, line) in lines.enumerate() {
        let line_number = line_index + 2;
        if line.trim().is_empty() {
            continue;
        }
        let columns: Vec<&str> = line.split('\t').collect();
        if columns.len() != 3 {
            return Err(format!(
                "red-label routine address line {line_number} must have 3 columns"
            ));
        }
        let label = columns[0];
        if label.is_empty() {
            return Err(format!(
                "red-label routine address line {line_number} has an empty label"
            ));
        }
        if columns[2].is_empty() {
            return Err(format!(
                "red-label routine address line {line_number} has an empty source"
            ));
        }
        if addresses
            .iter()
            .any(|entry: &RedLabelRoutineAddress| entry.label == label)
        {
            return Err(format!(
                "red-label routine address line {line_number} duplicates label `{label}`"
            ));
        }
        addresses.push(RedLabelRoutineAddress {
            label: String::from(label),
            address: parse_routine_address(columns[1], line_number)?,
        });
    }

    if addresses.is_empty() {
        return Err(String::from(
            "red-label routine address asset has no records",
        ));
    }
    Ok(addresses)
}

fn parse_routine_address(value: &str, line_number: usize) -> Result<u16, String> {
    let hex = value.strip_prefix("0x").ok_or_else(|| {
        format!("red-label routine address `{value}` on line {line_number} must start with 0x")
    })?;
    u16::from_str_radix(hex, 16).map_err(|_| {
        format!("red-label routine address `{value}` on line {line_number} is invalid")
    })
}

