    fn red_label_ram_crc(machine: &ArcadeMachine, range: std::ops::Range<u16>) -> u32 {
        crc32(
            machine
                .red_label_ram_range(range)
                .expect("red-label RAM range should be valid"),
        )
    }

    fn zero_bytes(range: std::ops::Range<u16>) -> Vec<u8> {
        vec![0; usize::from(range.end - range.start)]
    }

    fn screen_clear() -> RedLabelScreenClear {
        RedLabelScreenClear {
            start: 0,
            end: 0x9C00,
            bytes_cleared: 0x9C00,
        }
    }

    fn active_screen_clear() -> RedLabelScreenClear {
        RedLabelScreenClear {
            start: 0x002A,
            end: 0x9C00,
            bytes_cleared: 0x8268,
        }
    }

    fn credit_backup(value: u8) -> super::RedLabelCmosByteWrite {
        super::RedLabelCmosByteWrite {
            symbol: "CREDST",
            offset: 0x7D,
            value,
        }
    }

    fn write_shell_footprint(machine: &mut ArcadeMachine, screen_address: u16, value: u8) {
        for offset in [0, 1, 2, 0x100, 0x101, 0x102] {
            machine
                .memory
                .write_byte(screen_address + offset, value)
                .expect("write shell footprint byte");
        }
    }

    fn write_star_entry(
        memory: &mut super::RedLabelRuntimeMemory,
        entry_index: u16,
        x: u8,
        y: u8,
        color: u8,
    ) {
        let base = 0xAF9D + entry_index * 4;
        memory.write_byte(base, x).expect("write star x");
        memory.write_byte(base + 1, y).expect("write star y");
        memory
            .write_byte(base + 2, color)
            .expect("write star color");
    }

    fn fill_source_valid_stars(memory: &mut super::RedLabelRuntimeMemory) {
        for entry_index in 0..16 {
            let x = 0x10 + entry_index as u8;
            let y = 0x50 + entry_index as u8;
            let color = (entry_index as u8).wrapping_mul(0x11) & 0x77;
            write_star_entry(memory, entry_index, x, y, color);
        }
    }

    fn setup_collision_bomb_shell(
        machine: &mut ArcadeMachine,
        screen_address: u16,
        collision_vector_address: u16,
    ) -> u16 {
        let source = machine
            .red_label_get_object_cell()
            .expect("get firing object cell");
        machine.memory.write_word(0xA020, 0x2000).expect("set BGL");
        machine
            .memory
            .write_word(source + 0x0A, 0x2400)
            .expect("set source OX16");
        machine
            .memory
            .write_word(source + 0x0C, 0x5001)
            .expect("set source OY16");
        let shell = machine
            .red_label_get_shell_cell(
                source,
                0x4444,
                RedLabelShellDescriptor {
                    output_routine_address: red_label_routine_address("BMBOUT")
                        .expect("BMBOUT address"),
                    picture_address: red_label_object_picture_address("BMBP1")
                        .expect("BMBP1 address"),
                    kill_routine_address: collision_vector_address,
                },
            )
            .expect("get shell")
            .expect("allocated shell")
            .shell_address;
        machine
            .memory
            .write_word(shell + 0x04, screen_address)
            .expect("set shell screen address");
        machine
            .memory
            .write_word(shell + 0x0A, 0x1000)
            .expect("set shell OX16");
        machine
            .memory
            .write_word(shell + 0x0C, 0x5003)
            .expect("set shell OY16");
        shell
    }

    fn setup_kilp_enemy_object(
        machine: &mut ArcadeMachine,
        picture_label: &str,
        collision_label: &str,
        scanner_color: u16,
        screen_address: u16,
        x16: u16,
        y16: u16,
    ) -> (u16, u16) {
        let process = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make enemy process")
            .process_address;
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address(picture_label)
                        .unwrap_or_else(|_| panic!("{picture_label} address")),
                    collision_vector_address: red_label_routine_address(collision_label)
                        .unwrap_or_else(|_| panic!("{collision_label} address")),
                    scanner_color,
                },
            )
            .expect("init enemy object")
            .object_address;
        machine
            .red_label_activate_object_cell(object)
            .expect("activate enemy object");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(object + 0x04, screen_address)
            .expect("set object screen address");
        machine
            .memory
            .write_word(object + 0x0A, x16)
            .expect("set object OX16");
        machine
            .memory
            .write_word(object + 0x0C, y16)
            .expect("set object OY16");
        machine
            .memory
            .write_byte(0xA08B, 1)
            .expect("set current player");
        machine
            .memory
            .write_word(0xA08D, 0xA1C2)
            .expect("set current player record");
        (process, object)
    }

    fn setup_active_display_object(machine: &mut ArcadeMachine, picture_label: &str) -> u16 {
        let process = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make display process")
            .process_address;
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address(picture_label)
                        .unwrap_or_else(|_| panic!("{picture_label} address")),
                    collision_vector_address: red_label_routine_address("NOKILL")
                        .expect("NOKILL address"),
                    scanner_color: 0,
                },
            )
            .expect("init display object")
            .object_address;
        machine
            .red_label_activate_object_cell(object)
            .expect("activate display object");
        object
    }

    fn assert_shell_footprint_cleared(machine: &ArcadeMachine, screen_address: u16) {
        for offset in [0, 1, 2, 0x100, 0x101, 0x102] {
            assert_eq!(
                machine.red_label_ram_range(screen_address + offset..screen_address + offset + 1),
                Some(&[0][..]),
                "shell footprint byte 0x{:04X} was not cleared",
                screen_address + offset
            );
        }
    }

    fn write_object_footprint(
        machine: &mut ArcadeMachine,
        screen_address: u16,
        picture_address: u16,
        value: u8,
    ) {
        let picture = red_label_object_picture(picture_address).expect("object picture");
        for column in 0..picture.width {
            for row in 0..picture.height {
                let address = screen_address + (u16::from(column) << 8) + u16::from(row);
                machine
                    .memory
                    .write_byte(address, value)
                    .expect("write object footprint byte");
            }
        }
    }

    fn assert_object_footprint_cleared(
        machine: &ArcadeMachine,
        screen_address: u16,
        picture_address: u16,
    ) {
        let picture = red_label_object_picture(picture_address).expect("object picture");
        for column in 0..picture.width {
            for row in 0..picture.height {
                let address = screen_address + (u16::from(column) << 8) + u16::from(row);
                assert_eq!(
                    machine.red_label_ram_range(address..address + 1),
                    Some(&[0][..]),
                    "object footprint byte 0x{address:04X} was not cleared"
                );
            }
        }
    }

    fn assert_object_image_written(
        machine: &ArcadeMachine,
        screen_address: u16,
        picture_address: u16,
        image_address: u16,
    ) {
        let picture = red_label_object_picture(picture_address).expect("object picture");
        for column in 0..picture.width {
            for row in 0..picture.height {
                let screen_byte_address =
                    screen_address + (u16::from(column) << 8) + u16::from(row);
                let image_byte_address =
                    image_address + u16::from(column) * u16::from(picture.height) + u16::from(row);
                let expected = red_label_object_image_byte_required(image_byte_address, picture)
                    .expect("object image byte");
                assert_eq!(
                    machine.red_label_ram_range(screen_byte_address..screen_byte_address + 1),
                    Some(&[expected][..]),
                    "screen byte 0x{screen_byte_address:04X} did not match image byte 0x{image_byte_address:04X}"
                );
            }
        }
    }

    fn assert_message_glyph_first_column(
        machine: &ArcadeMachine,
        screen_address: u16,
        character: char,
    ) {
        let glyph = red_label_message_glyph(character).expect("message glyph");
        assert_eq!(
            machine.red_label_ram_range(screen_address..screen_address + u16::from(glyph.height)),
            Some(&glyph.bytes[..usize::from(glyph.height)]),
            "glyph `{character}` first column at 0x{screen_address:04X} did not match"
        );
    }

    fn assert_score_digit_first_column(machine: &ArcadeMachine, screen_address: u16, digit: u8) {
        let image = red_label_score_digit_image(digit).expect("score digit");
        assert_eq!(
            machine.red_label_ram_range(screen_address..screen_address + u16::from(image.height)),
            Some(&image.bytes[..usize::from(image.height)]),
            "score digit `{digit}` first column at 0x{screen_address:04X} did not match"
        );
    }

    fn seed_thrust_table(machine: &mut ArcadeMachine) {
        let rand_values: Vec<u8> = (0x10..=0x30).collect();
        machine
            .memory
            .initialize_thrust_table_from_rand_values(&rand_values)
            .expect("THINIT");
    }

    fn seed_whole_defender_descriptor(machine: &mut ArcadeMachine) {
        machine
            .memory
            .write_word(
                RED_LABEL_ATTRACT_DEFENDER_DESCRIPTOR,
                u16::from_be_bytes([
                    RED_LABEL_ATTRACT_DEFENDER_WHOLE_WIDTH,
                    RED_LABEL_ATTRACT_DEFENDER_WHOLE_HEIGHT,
                ]),
            )
            .expect("write DEFDSC size");
        machine
            .memory
            .write_word(
                RED_LABEL_ATTRACT_DEFENDER_DESCRIPTOR + 2,
                RED_LABEL_ATTRACT_DEFENDER_DATA,
            )
            .expect("write DEFDSC data pointer");
        for (offset, byte) in expanded_defender_logo_image().into_iter().enumerate() {
            machine
                .memory
                .write_byte(
                    RED_LABEL_ATTRACT_DEFENDER_DATA
                        + u16::try_from(offset).expect("DEFBLK offset fits"),
                    byte,
                )
                .expect("write DEFBLK byte");
        }
    }

    fn write_forward_thrust_footprint(machine: &mut ArcadeMachine, screen_address: u16, value: u8) {
        let origin = screen_address - 0x100 + 1;
        for address in [
            origin,
            origin + 1,
            origin + 2,
            origin + 3,
            origin + 4,
            origin - 0x100 + 1,
            origin - 0x100 + 2,
            origin - 0x100 + 3,
            origin - 0x200 + 1,
            origin - 0x200 + 2,
            origin - 0x200 + 3,
            origin - 0x300 + 2,
        ] {
            machine
                .memory
                .write_byte(address, value)
                .expect("write forward thrust footprint byte");
        }
    }

    fn write_backward_thrust_footprint(
        machine: &mut ArcadeMachine,
        screen_address: u16,
        value: u8,
    ) {
        let origin = screen_address + 0x801;
        for address in [
            origin,
            origin + 1,
            origin + 2,
            origin + 3,
            origin + 4,
            origin + 0x101,
            origin + 0x102,
            origin + 0x103,
            origin + 0x201,
            origin + 0x202,
            origin + 0x203,
            origin + 0x302,
        ] {
            machine
                .memory
                .write_byte(address, value)
                .expect("write backward thrust footprint byte");
        }
    }

    fn write_ram_bytes(machine: &mut ArcadeMachine, address: u16, bytes: &[u8]) {
        for (offset, byte) in bytes.iter().copied().enumerate() {
            machine
                .memory
                .write_byte(address + offset as u16, byte)
                .expect("write RAM byte");
        }
    }

    fn seed_hof_initials(
        machine: &mut ArcadeMachine,
        initials: [u8; RED_LABEL_INITIALS_ENTRY_CHARS],
    ) {
        for (index, initial) in initials.iter().copied().enumerate() {
            let address = RED_LABEL_HOF_INITS_RAM
                + u16::try_from(index * 2).expect("initial index should fit in u16");
            machine
                .memory
                .write_byte(address, initial)
                .expect("write HOF initial");
            machine
                .memory
                .write_byte(address + 1, b'/')
                .expect("write HOF initial terminator");
        }
    }

    fn seed_hof_up_down_input(machine: &mut ArcadeMachine, pia21: u8, pia31: u8) {
        machine
            .memory
            .write_byte(0xA07B, pia21)
            .expect("write source PIA21 input");
        machine
            .memory
            .write_byte(0xA07D, pia31)
            .expect("write source PIA31 input");
    }

    fn high_score_player_score_pointer(player_index: u16) -> u16 {
        let layout = red_label_ram_layout().expect("RAM layout");
        ram_field(&layout, "player", "PSCOR")
            .expect("player PSCOR field")
            .field_range_for_entry(player_index)
            .expect("player score range")
            .start
    }

    fn seed_hall6_submission(
        machine: &mut ArcadeMachine,
        player: u8,
        score: u32,
        initials: [u8; RED_LABEL_INITIALS_ENTRY_CHARS],
        entry_flag: u8,
    ) -> u16 {
        let layout = red_label_ram_layout().expect("RAM layout");
        let player_index = u16::from(player - 1);
        machine
            .memory
            .write_player_score_value(&layout, player_index, score)
            .expect("seed player score");
        let score_pointer = high_score_player_score_pointer(player_index);
        machine
            .memory
            .write_byte(RED_LABEL_HOF_PLAYER_NUMBER_RAM, player)
            .expect("seed PNUMB");
        machine
            .memory
            .write_word(RED_LABEL_HOF_PLAYER_SCORE_POINTER_RAM, score_pointer)
            .expect("seed PSCORE");
        machine
            .memory
            .write_byte(RED_LABEL_ATTRACT_ENTRY_FLAG_RAM, entry_flag)
            .expect("seed ENTFLG");
        seed_hof_initials(machine, initials);
        score_pointer
    }

    fn seed_high_score_table(
        machine: &mut ArcadeMachine,
        table: super::RuntimeHighScoreTable,
        top_score: u32,
    ) {
        for index in 0..RED_LABEL_HIGH_SCORE_ENTRIES {
            machine
                .memory
                .write_high_score_entry(
                    table,
                    index,
                    super::RuntimeHighScoreEntry {
                        score: top_score.saturating_sub(
                            u32::try_from(index).expect("index should fit in u32") * 100,
                        ),
                        initials: [b'A', b'A', b'A'],
                    },
                )
                .expect("seed high-score table");
        }
    }

    fn make_live_game_over_sleeping_process(machine: &mut ArcadeMachine, score: u32) -> u16 {
        let mut snapshot = machine.snapshot();
        snapshot.phase = GamePhase::Playing;
        machine.restore(snapshot);
        let layout = red_label_ram_layout().expect("RAM layout");
        machine
            .memory
            .write_player_score_value(&layout, 0, score)
            .expect("seed player-one score");
        machine.memory.write_byte(0xA112, 1).expect("set LNDCNT");
        machine.memory.write_byte(0xA08B, 1).expect("set CURPLR");
        machine.memory.write_byte(0xA08C, 1).expect("set PLRCNT");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine.memory.write_byte(0xA1C9, 0).expect("clear PLAS");
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PDTH5R").expect("PDTH5R address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PDTH5R process")
            .process_address;

        let dispatch = machine
            .step_red_label_translated_process()
            .expect("dispatch PDTH5R")
            .expect("scheduled PDTH5R");

        assert!(matches!(
            dispatch,
            RedLabelProcessDispatch::PlayerDeath(RedLabelPlayerDeath::GameOverSleeping { .. })
        ));
        assert_eq!(machine.snapshot().phase, GamePhase::GameOver);
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xDB, 0x48, 40][..])
        );
        process
    }

    fn scanner_object_screen_address_for_test(x16: u16, y16: u16, scan_left: u16) -> u16 {
        let x_byte = x16.wrapping_sub(scan_left).to_be_bytes()[0] >> 2;
        let y_byte = y16.to_be_bytes()[0] >> 3;
        u16::from_be_bytes([x_byte, y_byte]).wrapping_add(0x3007)
    }

