    #[test]
    fn power_up_ram_fill_mutates_observed_pass_ranges() {
        let mut machine = ArcadeMachine::new_cold_boot_trace();

        for _ in 0..74 {
            machine.step(CabinetInput::NONE);
        }

        assert_eq!(red_label_ram_crc(&machine, 0x0000..0xC000), 0x6EE2_63D2);

        let first_pass = red_label_ram_snapshot(
            &machine,
            "power-up second-pass rewritten range",
            0x0000..0xC000,
        );
        for _ in 74..247 {
            machine.step(CabinetInput::NONE);
        }

        first_pass.assert_current_changed(&machine);
        assert_eq!(red_label_ram_crc(&machine, 0x0000..0xC000), 0x613F_AF0E);
    }

    #[test]
    fn power_on_frame_model_tracks_source_boot_boundaries() {
        let cases = [
            (
                67,
                super::RedLabelPowerOnStage::ResetHold,
                0x0000,
                true,
                false,
            ),
            (
                68,
                super::RedLabelPowerOnStage::RamTestFirstPass,
                0xA26A,
                true,
                false,
            ),
            (
                75,
                super::RedLabelPowerOnStage::RamTestBetweenPasses,
                0xC000,
                true,
                false,
            ),
            (
                240,
                super::RedLabelPowerOnStage::RamTestSecondPass,
                0xA070,
                true,
                false,
            ),
            (
                248,
                super::RedLabelPowerOnStage::RamTestComplete,
                0xC000,
                true,
                false,
            ),
            (
                732,
                super::RedLabelPowerOnStage::Init20ObjectLists,
                0xC000,
                true,
                false,
            ),
            (
                733,
                super::RedLabelPowerOnStage::ExecIdleSeed,
                0xC000,
                false,
                false,
            ),
            (
                745,
                super::RedLabelPowerOnStage::ExecIdleSeed,
                0xC000,
                false,
                false,
            ),
            (
                746,
                super::RedLabelPowerOnStage::StartReady,
                0xC000,
                false,
                true,
            ),
        ];

        for (frame, stage, ram_fill_target, live_io_blocked, start_ready) in cases {
            let model = super::red_label_power_on_frame_model(frame).expect("power-on model");

            assert_eq!(model.frame, frame);
            assert_eq!(model.stage, stage);
            assert_eq!(model.ram_fill_target, ram_fill_target);
            assert_eq!(model.live_io_blocked, live_io_blocked);
            assert_eq!(model.start_ready, start_ready);
        }
    }

    #[test]
    fn power_on_frame_model_records_sinit_and_init20_mutations() {
        let layout = red_label_ram_layout().expect("RAM layout");
        let seed_end = super::field_range(&layout, "base_page", "LSEED")
            .expect("LSEED range")
            .end;

        let zero_seed = super::red_label_power_on_frame_model(720).expect("frame 720 model");
        assert_eq!(zero_seed.stage, super::RedLabelPowerOnStage::SinitZeroSeed);
        assert_eq!(zero_seed.sinit_clear_target, Some(seed_end));
        assert_eq!(
            zero_seed.rand_state,
            Some(super::RED_LABEL_TRACE_ZERO_RAND_STATE)
        );
        assert_eq!(zero_seed.phase, Some(GamePhase::Playing));

        let clear_player = super::red_label_power_on_frame_model(721).expect("frame 721 model");
        assert_eq!(
            clear_player.stage,
            super::RedLabelPowerOnStage::SinitClearPlayer
        );
        assert_eq!(clear_player.sinit_clear_target, Some(0xA4AC));
        assert_eq!(
            clear_player.rand_state,
            Some(super::RED_LABEL_TRACE_ZERO_RAND_STATE)
        );
        assert_eq!(clear_player.phase, Some(GamePhase::Attract));

        let clear_tail = super::red_label_power_on_frame_model(724).expect("frame 724 model");
        assert_eq!(
            clear_tail.stage,
            super::RedLabelPowerOnStage::SinitClearObjects
        );
        assert_eq!(clear_tail.sinit_clear_target, Some(0xAD89));

        let clear_complete = super::red_label_power_on_frame_model(725).expect("frame 725 model");
        assert_eq!(
            clear_complete.stage,
            super::RedLabelPowerOnStage::SinitClearComplete
        );
        assert_eq!(clear_complete.sinit_clear_target, Some(0xC000));
        assert_eq!(clear_complete.phase, Some(GamePhase::Attract));

        let clear_hold = super::red_label_power_on_frame_model(726).expect("frame 726 model");
        assert_eq!(
            clear_hold.stage,
            super::RedLabelPowerOnStage::SinitClearComplete
        );
        assert_eq!(clear_hold.sinit_clear_target, None);
        assert_eq!(
            clear_hold.rand_state,
            Some(super::RED_LABEL_TRACE_ZERO_RAND_STATE)
        );

        let init20_sound = super::red_label_power_on_frame_model(731).expect("frame 731 model");
        assert_eq!(init20_sound.stage, super::RedLabelPowerOnStage::Init20Sound);
        assert_eq!(
            init20_sound.rand_state,
            Some(super::RED_LABEL_TRACE_INIT20_SOUND_RAND_STATE)
        );
        assert_eq!(init20_sound.phase, Some(GamePhase::Attract));
        assert_eq!(init20_sound.sound_command_port_b, Some(0x00));
        assert!(init20_sound.initializes_process_lists);

        let init20_lists = super::red_label_power_on_frame_model(732).expect("frame 732 model");
        assert_eq!(
            init20_lists.stage,
            super::RedLabelPowerOnStage::Init20ObjectLists
        );
        assert_eq!(
            init20_lists.rand_state,
            Some(super::RED_LABEL_TRACE_INIT20_OBJECT_LIST_RAND_STATE)
        );
        assert_eq!(init20_lists.phase, Some(GamePhase::GameOver));
        assert!(!init20_lists.initializes_process_lists);
        assert!(init20_lists.initializes_object_lists);

        let exec_idle = super::red_label_power_on_frame_model(733).expect("frame 733 model");
        assert_eq!(
            exec_idle.rand_state,
            Some(super::RED_LABEL_TRACE_EXEC_IDLE_RAND_STATE)
        );
        assert_eq!(exec_idle.phase, None);
    }

    #[test]
    fn trace_power_on_handoff_applies_model_mutations() {
        let mut machine = ArcadeMachine::new_cold_boot_trace();
        let layout = red_label_ram_layout().expect("RAM layout");
        let seed_range = super::field_range(&layout, "base_page", "LSEED").expect("LSEED range");
        let status_range =
            super::field_range(&layout, "base_page", "STATUS").expect("STATUS range");
        let mut sound_commands = Vec::new();

        machine
            .memory
            .write_byte(0x9C00, 0xAA)
            .expect("seed SINIT byte");
        machine
            .memory
            .write_byte(seed_range.start, 0x55)
            .expect("seed LSEED byte");
        machine.frame = 720;
        machine
            .apply_trace_power_up_handoff(&mut sound_commands, false)
            .expect("frame 720 handoff");

        assert_eq!(
            machine
                .memory
                .read_byte(0x9C00)
                .expect("SINIT clear start byte"),
            0
        );
        assert_eq!(
            machine
                .memory
                .read_byte(seed_range.start)
                .expect("LSEED byte"),
            0
        );
        assert_eq!(
            machine.snapshot().rng,
            super::RED_LABEL_TRACE_ZERO_RAND_STATE
        );
        assert_eq!(machine.snapshot().phase, GamePhase::Playing);

        machine.frame = 731;
        machine
            .apply_trace_power_up_handoff(&mut sound_commands, false)
            .expect("frame 731 handoff");

        assert_eq!(
            machine.snapshot().rng,
            super::RED_LABEL_TRACE_INIT20_SOUND_RAND_STATE
        );
        assert_eq!(machine.snapshot().phase, GamePhase::Attract);
        assert_eq!(
            sound_commands
                .iter()
                .map(|command| command.raw())
                .collect::<Vec<_>>(),
            vec![0xC0]
        );

        machine
            .memory
            .write_byte(status_range.start, 0x00)
            .expect("clear STATUS");
        machine.frame = 732;
        machine
            .apply_trace_power_up_handoff(&mut sound_commands, false)
            .expect("frame 732 handoff");

        assert_eq!(
            machine.snapshot().rng,
            super::RED_LABEL_TRACE_INIT20_OBJECT_LIST_RAND_STATE
        );
        assert_eq!(machine.snapshot().phase, GamePhase::GameOver);
        assert_eq!(
            machine
                .memory
                .read_byte(status_range.start)
                .expect("STATUS byte"),
            0xFF
        );

        machine.frame = 733;
        machine
            .apply_trace_power_up_handoff(&mut sound_commands, false)
            .expect("frame 733 handoff");
        assert_eq!(
            machine.snapshot().rng,
            super::RED_LABEL_TRACE_EXEC_IDLE_RAND_STATE
        );

        let mut expected = super::RED_LABEL_TRACE_EXEC_IDLE_RAND_STATE;
        expected.advance();
        machine.frame = 746;
        machine
            .apply_trace_power_up_handoff(&mut sound_commands, false)
            .expect("frame 746 handoff");
        assert_eq!(machine.snapshot().rng, expected);
    }

    #[test]
    fn sinit_handoff_clears_each_observed_ram_segment() {
        let mut machine = ArcadeMachine::new_cold_boot_trace();
        let layout = red_label_ram_layout().expect("RAM layout");
        let seed_range = super::field_range(&layout, "base_page", "LSEED").expect("LSEED range");
        let seeded_range = 0x9C00..0xC000;
        machine
            .memory
            .write_range(seeded_range.clone(), &vec![0xA5; seeded_range.len()])
            .expect("seed SINIT clear window");
        let mut sound_commands = Vec::new();

        for (frame, range) in [
            (720, 0x9C00..seed_range.end),
            (721, seed_range.end..0xA4AC),
            (722, 0xA4AC..0xA7A0),
            (723, 0xA7A0..0xAA94),
            (724, 0xAA94..0xAD89),
            (725, 0xAD89..0xC000),
        ] {
            let before = red_label_ram_snapshot(&machine, "SINIT clear segment", range.clone());

            machine.frame = frame;
            machine
                .apply_trace_power_up_handoff(&mut sound_commands, false)
                .expect("SINIT handoff frame");

            before.assert_current_changed_to(&machine, &zero_bytes(range));
        }

        assert!(sound_commands.is_empty());
    }

    #[test]
    fn init20_handoff_mutates_list_score_status_and_latch_ranges() {
        let layout = red_label_ram_layout().expect("RAM layout");
        let lists = red_label_linked_lists().expect("linked-list layout");
        let process = super::table_descriptor(&layout, "process").expect("process table");
        let super_process =
            super::table_descriptor(&layout, "super_process").expect("super-process table");
        let object = super::table_descriptor(&layout, "object").expect("object table");
        let process_range = process.table_range().expect("process range");
        let super_process_range = super_process.table_range().expect("super-process range");
        let object_range = object.table_range().expect("object range");
        let process_base = process.base.to_be_bytes();
        let super_process_base = super_process.base.to_be_bytes();
        let object_base = object.base.to_be_bytes();
        let next_process_base = (process.base + process.entry_size).to_be_bytes();
        let high_score_cells =
            u16::try_from(RED_LABEL_HIGH_SCORE_ENTRIES * RED_LABEL_HIGH_SCORE_ENTRY_CELLS)
                .expect("today's high-score table size fits u16");
        let todays_range = RED_LABEL_THSTAB_START..RED_LABEL_THSTAB_START + high_score_cells;
        let status_range =
            super::field_range(&layout, "base_page", "STATUS").expect("STATUS range");
        let crproc_range =
            super::field_range(&layout, "runtime_pointers", "CRPROC").expect("CRPROC range");
        let free_process_head = super::linked_list(&lists, "free_process")
            .expect("free_process list")
            .head_address;
        let free_super_process_head = super::linked_list(&lists, "free_super_process")
            .expect("free_super_process list")
            .head_address;
        let active_process_head = super::linked_list(&lists, "active_process")
            .expect("active_process list")
            .head_address;
        let active_process_head_bytes = active_process_head.to_be_bytes();
        let free_object_head = super::linked_list(&lists, "free_object")
            .expect("free_object list")
            .head_address;
        let active_object_head = super::linked_list(&lists, "active_object")
            .expect("active_object list")
            .head_address;
        let inactive_object_head = super::linked_list(&lists, "inactive_object")
            .expect("inactive_object list")
            .head_address;
        let shell_object_head = super::linked_list(&lists, "shell_object")
            .expect("shell_object list")
            .head_address;

        let mut machine = ArcadeMachine::new_cold_boot_trace();
        for _ in 0..730 {
            machine.step(CabinetInput::NONE);
        }
        let process_before_init =
            red_label_ram_snapshot(&machine, "INIT20 process-list init", process_range.clone());
        let super_process_before_init = red_label_ram_snapshot(
            &machine,
            "INIT20 super-process-list init",
            super_process_range.clone(),
        );
        machine.step(CabinetInput::NONE);
        let sound_before = machine.red_label_sound_board_snapshot();
        process_before_init.assert_current_changed(&machine);
        super_process_before_init.assert_current_changed(&machine);
        assert_eq!(
            red_label_ram_crc(&machine, process_range.clone()),
            0xB2B2_58E3
        );
        assert_eq!(
            red_label_ram_crc(&machine, super_process_range.clone()),
            0x5EDF_4A6B
        );

        let todays = red_label_ram_snapshot(&machine, "INIT20 today's scores", todays_range);
        let status = red_label_ram_snapshot(&machine, "INIT20 STATUS", status_range.clone());
        let process_table =
            red_label_ram_snapshot(&machine, "INIT20 process table", process_range.clone());
        let super_process_table = red_label_ram_snapshot(
            &machine,
            "INIT20 super-process table",
            super_process_range.clone(),
        );
        let object_table =
            red_label_ram_snapshot(&machine, "INIT20 object table", object_range.clone());

        machine.step(CabinetInput::NONE);

        assert_eq!(
            sound_before,
            RedLabelSoundBoardSnapshot {
                last_command_latch: Some(SoundCommandLatch::from_main_board_pia_port_b(0xC0)),
                latched_port_b: Some(0xC0),
                command_cb1_asserted: true,
                latch_write_count: 1,
            }
        );
        assert_eq!(machine.red_label_sound_board_snapshot(), sound_before);
        todays.assert_current_changed(&machine);
        status.assert_current_changed_to(&machine, &[0xFF]);
        process_table.assert_current_changed(&machine);
        super_process_table.assert_current_unchanged(&machine);
        object_table.assert_current_changed(&machine);
        assert_eq!(red_label_ram_crc(&machine, process_range), 0xA424_BDF6);
        assert_eq!(
            red_label_ram_crc(&machine, super_process_range),
            0x5EDF_4A6B
        );
        assert_eq!(red_label_ram_crc(&machine, object_range), 0x9075_E2DD);
        assert_eq!(red_label_ram_crc(&machine, todays.range()), 0xE50A_C8F3);
        assert_eq!(
            machine.red_label_ram_range(free_process_head..free_process_head + 2),
            Some(&next_process_base[..])
        );
        assert_eq!(
            machine.red_label_ram_range(free_super_process_head..free_super_process_head + 2),
            Some(&super_process_base[..])
        );
        assert_eq!(
            machine.red_label_ram_range(active_process_head..active_process_head + 2),
            Some(&process_base[..])
        );
        assert_eq!(
            machine.red_label_ram_range(crproc_range),
            Some(&active_process_head_bytes[..])
        );
        assert_eq!(
            machine.red_label_ram_range(free_object_head..free_object_head + 2),
            Some(&object_base[..])
        );
        assert_eq!(
            machine.red_label_ram_range(active_object_head..active_object_head + 2),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(inactive_object_head..inactive_object_head + 2),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(shell_object_head..shell_object_head + 2),
            Some(&[0, 0][..])
        );
    }

