    #[test]
    fn fplay_uses_free_play_cmos_byte_to_seed_credits() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA037, 0x01).expect("set CREDIT");

        let paid_play = machine
            .red_label_apply_free_play_credit()
            .expect("FPLAY with default paid play");

        assert_eq!(
            paid_play,
            RedLabelFreePlayCredit {
                free_play: 0,
                credit_before: 0x01,
                credit_after: 0x01,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA037..0xA038),
            Some(&[0x01][..])
        );

        let mut machine = ArcadeMachine::new();
        machine
            .memory
            .write_cmos_byte_by_symbol("FREEPL", 1)
            .expect("set FREEPL");
        let free_play = machine
            .red_label_apply_free_play_credit()
            .expect("FPLAY with FREEPL set");

        assert_eq!(
            free_play,
            RedLabelFreePlayCredit {
                free_play: 1,
                credit_before: 0x00,
                credit_after: 0x02,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA037..0xA038),
            Some(&[0x02][..])
        );
    }

    #[test]
    fn start2_credit_tail_increments_player_count_and_decrements_bcd_credit() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA08C, 0x00).expect("set PLRCNT");
        machine.memory.write_byte(0xA037, 0x01).expect("set CREDIT");

        let one_player = machine
            .red_label_advance_start_credit_tail()
            .expect("START2 credit tail");

        assert_eq!(
            one_player,
            RedLabelStartCredit {
                player_count_before: 0x00,
                player_count_after: 0x01,
                credit_before: 0x01,
                credit_after: 0x00,
                credit_cmos_backup: credit_backup(0x00),
                top_display_required: false,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA037..0xA038),
            Some(&[0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA08C..0xA08D),
            Some(&[0x01][..])
        );
        assert_eq!(
            machine.red_label_cmos_range(0x7D..0x7F),
            Some(&[0xF0, 0xF0][..])
        );

        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA08C, 0x01).expect("set PLRCNT");
        machine.memory.write_byte(0xA037, 0x10).expect("set CREDIT");

        let two_player = machine
            .red_label_advance_start_credit_tail()
            .expect("START2 credit tail");

        assert_eq!(
            two_player,
            RedLabelStartCredit {
                player_count_before: 0x01,
                player_count_after: 0x02,
                credit_before: 0x10,
                credit_after: 0x09,
                credit_cmos_backup: credit_backup(0x09),
                top_display_required: true,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA037..0xA038),
            Some(&[0x09][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA08C..0xA08D),
            Some(&[0x02][..])
        );
        assert_eq!(
            machine.red_label_cmos_range(0x7D..0x7F),
            Some(&[0xF0, 0xF9][..])
        );
    }

