    #[test]
    fn start_switch_dispatch_blocks_status_or_insufficient_credit_then_dies() {
        let mut machine = ArcadeMachine::new();
        machine
            .red_label_make_process(
                red_label_routine_address("ST1").expect("ST1 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make ST1 process");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule ST1");
        machine.memory.write_byte(0xA0BA, 0x7F).expect("set STATUS");
        machine.memory.write_byte(0xA037, 0x05).expect("set CREDIT");

        assert_eq!(
            machine
                .red_label_dispatch_start_one_current_process()
                .expect("blocked ST1"),
            RedLabelStartSwitch::StatusBlocked {
                players: 1,
                status: 0x7F,
                killed_process: RedLabelKilledProcess {
                    killed_process_address: 0xAAC5,
                    previous_link_address: 0xA05F,
                },
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA037..0xA038),
            Some(&[0x05][..])
        );

        let mut machine = ArcadeMachine::new();
        machine
            .red_label_make_process(
                red_label_routine_address("ST2").expect("ST2 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make ST2 process");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule ST2");
        machine.memory.write_byte(0xA0BA, 0xFF).expect("set STATUS");
        machine.memory.write_byte(0xA037, 0x01).expect("set CREDIT");

        assert_eq!(
            machine
                .red_label_dispatch_start_two_current_process()
                .expect("insufficient-credit ST2"),
            RedLabelStartSwitch::InsufficientCredit {
                players: 2,
                free_play: RedLabelFreePlayCredit {
                    free_play: 0,
                    credit_before: 1,
                    credit_after: 1,
                },
                credit: 1,
                killed_process: RedLabelKilledProcess {
                    killed_process_address: 0xAAC5,
                    previous_link_address: 0xA05F,
                },
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
    }

    #[test]
    fn block_clear_matches_source_screen_format_stride() {
        let mut machine = ArcadeMachine::new();
        let top_left = 0x1234;
        for column in 0..4u16 {
            for row in 0..5u16 {
                let address = screen_offset(top_left, (column << 8) + row).expect("screen offset");
                machine
                    .memory
                    .write_byte(address, 0xAA)
                    .expect("seed screen byte");
            }
        }

        let cleared = machine
            .red_label_block_clear(top_left, 3, 4)
            .expect("BLKCLR");

        assert_eq!(
            cleared,
            RedLabelBlockClear {
                screen_address: top_left,
                width: 3,
                height: 4,
            }
        );
        for column in 0..4u16 {
            for row in 0..5u16 {
                let address = screen_offset(top_left, (column << 8) + row).expect("screen offset");
                let expected = if column < 3 && row < 4 { 0x00 } else { 0xAA };
                assert_eq!(
                    machine.red_label_ram_range(address..address + 1),
                    Some(&[expected][..]),
                    "column {column}, row {row}"
                );
            }
        }
    }

