    #[test]
    fn normal_irq_upper_object_band_pass_uses_xxx2_bounds_and_source_order() {
        let mut machine = ArcadeMachine::new();
        let picture_address = red_label_object_picture_address("BMBP1").expect("BMBP1 address");
        let object = setup_active_display_object(&mut machine, "BMBP1");
        machine.memory.write_byte(0xA0A2, 0x90).expect("set XXX2");
        machine.memory.write_byte(0xA0A3, 0x70).expect("set XXX3");
        machine
            .memory
            .write_byte(0xA0C0, 0xA0)
            .expect("set PLAYC outside band");
        machine.memory.write_word(0xA020, 0x1000).expect("set BGL");
        machine.memory.write_word(0xA022, 0x1000).expect("set BGLX");
        machine
            .memory
            .write_word(object + 0x0A, 0x1420)
            .expect("set object OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x8055)
            .expect("set object OY16");

        let pass = machine
            .red_label_run_normal_irq_upper_object_band_pass()
            .expect("normal IRQ upper object-band pass");

        assert_eq!(
            pass,
            RedLabelIrqObjectBandPass {
                phase: RedLabelIrqObjectBandPhase::NormalUpper,
                upper_bound: 0x90,
                lower_bound: 0x70,
                steps: vec![
                    RedLabelIrqObjectBandStep::Objects(RedLabelObjectDisplayBand::Updated {
                        status: 0,
                        upper_bound: 0x90,
                        lower_bound: 0x70,
                        objects: vec![RedLabelObjectDisplay {
                            object_address: object,
                            picture_address,
                            old_screen_address: None,
                            erased_old_picture: None,
                            relative_x: Some(0x0420),
                            new_screen_address: Some(0x1080),
                            alternate_flavor: Some(true),
                            written_picture: Some(RedLabelPictureWrite {
                                screen_address: 0x1080,
                                picture_address,
                                width: 2,
                                height: 3,
                            }),
                        }],
                    }),
                    RedLabelIrqObjectBandStep::Player(RedLabelPlayerDisplay::OutsideBand {
                        status: 0,
                        upper_bound: 0x90,
                        lower_bound: 0x70,
                        player_y: 0xA0,
                    }),
                    RedLabelIrqObjectBandStep::Shells {
                        steps: Vec::new(),
                        output_routines: Vec::new(),
                    },
                ],
            }
        );
        assert_eq!(
            machine.red_label_ram_range(object + 0x04..object + 0x06),
            Some(&[0x10, 0x80][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA077..0xA078),
            Some(&[0x90][..])
        );
    }

