    #[test]
    fn live_irq_video_frame_copies_pcram_into_palette_ram_for_native_rendering() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let palette_source = [
            0x10, 0x11, 0x12, 0x13, 0x20, 0x21, 0x22, 0x23, 0x24, 0x25, 0xD6, 0x29, 0x32, 0x33,
            0x34, 0x35,
        ];
        machine
            .memory
            .write_range(0xA026..0xA036, &palette_source)
            .expect("seed PCRAM");
        let palette_before = *machine.red_label_palette_ram();

        let frame = machine
            .red_label_run_normal_live_irq_video_frame()
            .expect("normal live IRQ video frame");

        assert_eq!(
            frame.lower_scanline.palette_copy,
            Some(RedLabelPaletteCopy {
                source_start: 0xA026,
                target_start: 0xC000,
                bytes_copied: PALETTE_RAM_SIZE as u8,
                palette_ram: palette_source,
            })
        );
        assert_ne!(palette_before, palette_source);
        assert_eq!(machine.red_label_palette_ram(), &palette_source);

        let visible_offset =
            defender_visible_byte_offset(0, 0).expect("visible origin maps into video RAM");
        machine
            .memory
            .write_byte(visible_offset as u16, 0xAB)
            .expect("seed visible origin");
        let image = machine
            .red_label_visible_rgba_image()
            .expect("render native frame through copied palette RAM");

        assert_eq!(&image.pixels[0..4], &[217, 81, 255, 255]);
        assert_eq!(&image.pixels[4..8], &[38, 174, 0, 255]);
    }

    #[test]
    fn live_irq_video_frame_has_scanline_sensitive_pixel_fixture() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let object = setup_active_display_object(&mut machine, "BMBP1");
        machine
            .memory
            .write_word(object + 0x0A, 0x1420)
            .expect("set object OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x8055)
            .expect("set object OY16");
        machine
            .memory
            .write_word(object + 0x0E, 0x0100)
            .expect("set object OXV");
        machine
            .memory
            .write_word(object + 0x10, 0x0200)
            .expect("set object OYV");
        let before = machine
            .red_label_visible_pixel_nibbles()
            .expect("pre-frame visible pixel nibbles");

        let frame = machine
            .red_label_run_normal_live_irq_video_frame()
            .expect("normal live IRQ video frame");
        let visible = machine
            .red_label_visible_pixel_nibbles()
            .expect("post-frame visible pixel nibbles");

        assert_eq!(
            frame.upper_object_band.phase,
            RedLabelIrqObjectBandPhase::NormalUpper
        );
        assert_eq!(
            frame.lower_object_band.phase,
            RedLabelIrqObjectBandPhase::NormalLower
        );
        assert_ne!(crc32(&visible), crc32(&before));
        assert_eq!(crc32(&visible), 0xB0E3_5EDE);
    }

