    #[test]
    fn fire_switch_scan_requires_two_clear_samples_then_queues_lfire() {
        let mut machine = ArcadeMachine::new();

        machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts {
                in0: 0x02,
                in1: 0x01,
                in2: 0,
            })
            .expect("sample thrust and up");
        let held = machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts {
                in0: 0x03,
                in1: 0,
                in2: 0,
            })
            .expect("fire with thrust still in two-frame history");

        assert_eq!(
            held,
            RedLabelSwitchScan {
                previous_pia21: 0x02,
                previous_pia22: 0x00,
                current_pia21: 0x03,
                current_pia31: 0x00,
                triggered_bits: 0x01,
                queued: Some(RedLabelSwitchProcess {
                    switch_bit: 0x01,
                    routine_address: red_label_routine_address("LFIRE").expect("LFIRE address"),
                    process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                    status_mask: 0xE8,
                }),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA07B..0xA07E),
            Some(&[0x03, 0x02, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA082..0xA086),
            Some(&[0xE5, 0x91, RED_LABEL_SYSTEM_PROCESS_TYPE, 0xE8][..])
        );

        machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts::EMPTY)
            .expect("release fire");
        let blocked_by_history = machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts {
                in0: 0x01,
                in1: 0,
                in2: 0,
            })
            .expect("one clear sample only");
        assert_eq!(blocked_by_history.queued, None);

        machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts::EMPTY)
            .expect("clear blocked sample");
        machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts::EMPTY)
            .expect("second clear sample");
        let retriggered = machine
            .red_label_scan_laser_fire_switch(DefenderInputPorts {
                in0: 0x01,
                in1: 0,
                in2: 0,
            })
            .expect("two clear samples");
        assert!(retriggered.queued.is_some());
    }

