    #[test]
    fn kill_process_unlinks_active_cell_and_returns_it_to_free_list() {
        let mut machine = ArcadeMachine::new();
        let first = machine
            .red_label_make_process(0x1111, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make first")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule first");
        let second = machine
            .red_label_make_process(0x2222, RED_LABEL_ATTRACT_PROCESS_TYPE)
            .expect("make second")
            .process_address;

        let previous_link = machine.red_label_kill_process(first).expect("kill first");

        assert_eq!(previous_link, 0xA05F);
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0xAA, 0xD4][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&[0xAA, 0xC5][..])
        );
        assert_eq!(
            machine.red_label_ram_range(first..first + 2),
            Some(&[0xAA, 0xE3][..])
        );

        let previous_link = machine.red_label_kill_process(second).expect("kill second");

        assert_eq!(previous_link, 0xA05F);
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&[0xAA, 0xD4][..])
        );
        assert_eq!(
            machine.red_label_ram_range(second..second + 2),
            Some(&[0xAA, 0xC5][..])
        );
    }

    #[test]
    fn kill_super_process_returns_cell_to_spfree() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_super_process(0x2468, RED_LABEL_COIN_PROCESS_TYPE)
            .expect("make super")
            .process_address;

        let previous_link = machine
            .red_label_kill_process(process)
            .expect("kill super process");

        assert_eq!(previous_link, 0xA05F);
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA069..0xA06B),
            Some(&[0xAF, 0x2A][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAF2A..0xAF2C),
            Some(&[0xAF, 0x41][..])
        );
    }

    #[test]
    fn genocide_kills_non_current_non_coin_processes() {
        let mut machine = ArcadeMachine::new();
        let current = machine
            .red_label_make_process(0x1111, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make current")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule current");
        let first_regular = machine
            .red_label_make_process(0x2222, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make first regular")
            .process_address;
        let coin = machine
            .red_label_make_process(0x3333, RED_LABEL_COIN_PROCESS_TYPE)
            .expect("make coin process")
            .process_address;
        let second_regular = machine
            .red_label_make_process(0x4444, RED_LABEL_ATTRACT_PROCESS_TYPE)
            .expect("make second regular")
            .process_address;

        let genocide = machine
            .red_label_genocide_other_processes()
            .expect("GNCIDE");

        assert_eq!(
            genocide,
            RedLabelGenocide {
                current_process_address: current,
                killed_processes: vec![
                    RedLabelKilledProcess {
                        killed_process_address: second_regular,
                        previous_link_address: current,
                    },
                    RedLabelKilledProcess {
                        killed_process_address: first_regular,
                        previous_link_address: coin,
                    },
                ],
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&current.to_be_bytes()[..])
        );
        assert_eq!(
            machine.red_label_ram_range(current..current + 2),
            Some(&coin.to_be_bytes()[..])
        );
        assert_eq!(
            machine.red_label_ram_range(coin..coin + 2),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&first_regular.to_be_bytes()[..])
        );
        assert_eq!(
            machine.red_label_ram_range(first_regular..first_regular + 2),
            Some(&second_regular.to_be_bytes()[..])
        );
    }

