    #[test]
    fn game_exec_star_time_restores_stars_and_advances_timer() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make GEXEC-like process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule GEXEC-like process");
        machine.memory.write_byte(0xA0AE, 15).expect("set STRCNT");
        machine.memory.write_byte(0xA024, 0xEF).expect("set GTIME");
        machine
            .memory
            .write_byte(process + 7, 2)
            .expect("set GEXEC delta counter");

        let first = machine
            .red_label_advance_game_exec_star_time()
            .expect("GEX3 star/time");
        let second = machine
            .red_label_advance_game_exec_star_time()
            .expect("GEX3 timer wrap");

        assert_eq!(
            first,
            RedLabelGameExecStarTime {
                process_address: process,
                previous_star_count: 15,
                star_count: 16,
                previous_game_time: 0xEF,
                game_time: 0xF0,
                audit_meter: None,
                previous_delta_counter: 2,
                delta_counter: 1,
                wave_delta: None,
            }
        );
        assert_eq!(
            second,
            RedLabelGameExecStarTime {
                process_address: process,
                previous_star_count: 16,
                star_count: 16,
                previous_game_time: 0xF0,
                game_time: 0x00,
                audit_meter: Some(0x06),
                previous_delta_counter: 1,
                delta_counter: 40,
                wave_delta: Some(RedLabelWaveDelta {
                    start_address: 0xA0FB,
                    bytes_updated: 23,
                    bytes_changed: 5,
                }),
            }
        );
        assert_eq!(machine.red_label_ram_range(0xA0AE..0xA0AF), Some(&[16][..]));
        assert_eq!(machine.red_label_ram_range(0xA024..0xA025), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(process + 7..process + 8),
            Some(&[40][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0FB..0xA112),
            Some(
                &[
                    0, 0, 0, 0, 0, 0, 0, 3, 0, 16, 0, 0, 0, 0, 8, 8, 0, 8, 0, 0, 0, 0, 0,
                ][..]
            )
        );
    }

