    #[test]
    fn astkil_collision_clears_target_kiloff_explodes_and_starts_terblo_when_empty() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("ASTRO").expect("ASTRO address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make ASTRO process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule ASTRO");
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("ASTP1")
                        .expect("ASTP1 address"),
                    collision_vector_address: red_label_routine_address("ASTKIL")
                        .expect("ASTKIL address"),
                    scanner_color: 0x6666,
                },
            )
            .expect("init astronaut object")
            .object_address;
        machine
            .red_label_activate_object_cell(object)
            .expect("activate astronaut object");
        machine
            .memory
            .write_word(0xA11A, object)
            .expect("set TLIST slot");
        machine.memory.write_byte(0xA0FA, 1).expect("set ASTCNT");
        machine.memory.write_byte(0xA0DE, 0).expect("clear PCFLG");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(object + 0x04, 0x5062)
            .expect("set OBJX");
        machine
            .memory
            .write_word(object + 0x0A, 0x2040)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x6200)
            .expect("set OY16");
        write_ram_bytes(&mut machine, 0x5062, &[0xFF, 0xFF]);
        write_ram_bytes(&mut machine, 0x5162, &[0xFF, 0xFF]);

        let collision = machine
            .red_label_dispatch_object_collision_vector(object)
            .expect("dispatch ASTKIL");
        let RedLabelObjectCollision::AstronautKilled(kill) = collision else {
            panic!("expected ASTKIL collision");
        };

        assert_eq!(
            kill,
            RedLabelAstronautKill::Killed {
                object_address: object,
                cleared_target_slot_address: 0xA11A,
                active_astronaut_count: 0,
                terrain_blow_process: Some(RedLabelCreatedProcess {
                    process_address: 0xAAD4,
                    routine_address: red_label_routine_address("TERBLO").expect("TERBLO address"),
                    process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                    class: RedLabelProcessClass::Regular,
                }),
                previous_object_link_address: 0xA065,
                adjusted_x16: 0x2000,
                explosion: RedLabelExplosionStart {
                    object_address: object,
                    picture_address: red_label_object_picture_address("ASXP1")
                        .expect("ASXP1 address"),
                    relative_x: 0x2000,
                    slot_address: Some(0x9C00),
                    erased_previous_slot: false,
                    top_left: Some(0x8062),
                    center: Some(0x8266),
                },
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4E4,
                    priority: 0xE0,
                }),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA11A..0xA11C),
            Some(&[0, 0][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA0FA..0xA0FB), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(object + 0x02..object + 0x0C),
            Some(&[0xF8, 0xD8, 0x50, 0x62, 0xAA, 0xC5, 0xED, 0x70, 0x20, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAD4 + 0x02..0xAAD4 + 0x06),
            Some(&[0xED, 0xEA, 0x01, RED_LABEL_SYSTEM_PROCESS_TYPE][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x5062..0x5064),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x5162..0x5164),
            Some(&[0, 0][..])
        );
    }

