    #[test]
    fn terrain_blow_start_erases_terrain_spawns_explosions_and_sleeps() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("TERBLO").expect("TERBLO address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make TERBLO process")
            .process_address;
        machine
            .memory
            .write_byte(process + 0x07, 0x55)
            .expect("dirty TERBLO PD");
        machine.memory.write_byte(0xA0BA, 0x80).expect("set STATUS");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine.memory.write_byte(0xA0DF, 0).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0).expect("set LSEED");
        machine
            .memory
            .write_word(0xBE20, 0x6000)
            .expect("seed STBL entry");
        machine
            .memory
            .write_word(0xBE22, 0x6100)
            .expect("seed second STBL entry");
        machine
            .memory
            .write_word(0xB125, 0x6200)
            .expect("seed STETAB entry");
        machine
            .memory
            .write_word(0xB127, 0x6300)
            .expect("seed second STETAB entry");
        write_ram_bytes(&mut machine, 0x6000, &[0xAA, 0xAA]);
        write_ram_bytes(&mut machine, 0x6100, &[0xBB, 0xBB]);
        write_ram_bytes(&mut machine, 0x6200, &[0xCC, 0xCC]);
        write_ram_bytes(&mut machine, 0x6300, &[0xDD, 0xDD]);

        let mut rand = RandState {
            seed: 0,
            hseed: 0,
            lseed: 0,
        };
        rand.advance();
        let first_rand = rand;
        let first_x = u16::from_be_bytes([first_rand.seed & 0x3F, 2]);
        rand.advance();
        let second_rand = rand;
        let second_x = u16::from_be_bytes([second_rand.seed & 0x3F, first_x.to_be_bytes()[1]]);
        machine
            .memory
            .write_byte(0xB300 + (first_x >> 6), 0x70)
            .expect("seed first altitude");
        machine
            .memory
            .write_byte(0xB300 + (second_x >> 6), 0x50)
            .expect("seed second altitude");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule TERBLO");

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("TERBLO").expect("TERBLO address"),
            )
            .expect("dispatch TERBLO");
        let RedLabelProcessDispatch::TerrainBlow(step) = dispatch else {
            panic!("expected TERBLO dispatch");
        };
        let RedLabelTerrainBlowProcessStep::StartedSleeping {
            process_address,
            status,
            terrain_erase,
            scanner_terrain_erase,
            pass,
        } = step
        else {
            panic!("expected TERBLO start step");
        };

        assert_eq!(process_address, process);
        assert_eq!(status, 0x82);
        assert_eq!(
            terrain_erase,
            RedLabelTerrainErase {
                table_start: 0xBE20,
                table_end: 0xBF50,
                entries: 0x98,
            }
        );
        assert_eq!(
            scanner_terrain_erase,
            RedLabelScannerTerrainErase {
                table_start: 0xB125,
                table_end: 0xB1A5,
                entries: 0x40,
            }
        );
        assert_eq!(
            pass,
            RedLabelTerrainExplosionPass {
                scratch_object_address: 0xA23C,
                explosions: vec![
                    RedLabelTerrainExplosion {
                        object_address: 0xA23C,
                        rand_state: first_rand,
                        x16: 0x1102,
                        altitude: 0x70,
                        center: 0x6602,
                        explosion: RedLabelExplosionStart {
                            object_address: 0xA23C,
                            picture_address: red_label_object_picture_address("TEREX")
                                .expect("TEREX address"),
                            relative_x: 0x1102,
                            slot_address: Some(0x9C00),
                            erased_previous_slot: false,
                            top_left: Some(0x4470),
                            center: Some(0x4873),
                        },
                    },
                    RedLabelTerrainExplosion {
                        object_address: 0xA23C,
                        rand_state: second_rand,
                        x16: 0x0402,
                        altitude: 0x50,
                        center: 0x4602,
                        explosion: RedLabelExplosionStart {
                            object_address: 0xA23C,
                            picture_address: red_label_object_picture_address("TEREX")
                                .expect("TEREX address"),
                            relative_x: 0x0402,
                            slot_address: Some(0x9C40),
                            erased_previous_slot: false,
                            top_left: Some(0x1050),
                            center: Some(0x1453),
                        },
                    },
                ],
                pseudo_color: 0x3C,
                overload_counter: 8,
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4E4,
                    priority: 0xE0,
                }),
                wakeup_address: red_label_routine_address("TBL3").expect("TBL3 address"),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0x6000..0x6002),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x6100..0x6102),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x6200..0x6202),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x6300..0x6302),
            Some(&[0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x08),
            Some(&[0xEE, 0x44, 0x02, RED_LABEL_SYSTEM_PROCESS_TYPE, 0, 0,][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0x3C][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA05E..0xA05F), Some(&[8][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA0F8..0xA0FA),
            Some(&[0x46, 0x02][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0DF..0xA0E2),
            Some(&[second_rand.seed, second_rand.hseed, second_rand.lseed][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD4, 0xE2, 0xE0, 0x01, 0x01][..])
        );
    }

