    #[test]
    fn terrain_blow_iteration_restarts_pass_until_final_sound_and_suicide() {
        let mut machine = ArcadeMachine::new();
        let loop_process = machine
            .red_label_make_process(
                red_label_routine_address("TBL4").expect("TBL4 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make looping TBL4 process")
            .process_address;
        machine
            .memory
            .write_byte(loop_process + 0x07, 0)
            .expect("set first iteration");
        machine.memory.write_byte(0xA0DF, 0).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0).expect("set LSEED");
        machine
            .memory
            .write_byte(0xB344, 0x70)
            .expect("seed altitude");
        machine
            .memory
            .write_byte(0xB310, 0x50)
            .expect("seed altitude");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule looping TBL4");

        let RedLabelTerrainBlowProcessStep::IterationAdvancedSleeping {
            process_address,
            iteration,
            pass,
        } = machine
            .red_label_advance_terrain_blow_iteration_current_process()
            .expect("TBL4 loop step")
        else {
            panic!("expected TBL4 loop");
        };

        assert_eq!(process_address, loop_process);
        assert_eq!(iteration, 1);
        assert_eq!(pass.explosions.len(), 2);
        assert_eq!(
            pass.wakeup_address,
            red_label_routine_address("TBL3").unwrap()
        );
        assert_eq!(
            machine.red_label_ram_range(loop_process + 0x02..loop_process + 0x08),
            Some(&[0xEE, 0x44, 0x02, RED_LABEL_SYSTEM_PROCESS_TYPE, 0, 1,][..])
        );

        let final_process = machine
            .red_label_make_process(
                red_label_routine_address("TBL4").expect("TBL4 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make final TBL4 process")
            .process_address;
        machine
            .memory
            .write_byte(final_process + 0x07, 15)
            .expect("set final iteration");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule final TBL4");

        let step = machine
            .red_label_advance_terrain_blow_iteration_current_process()
            .expect("TBL4 final step");

        assert_eq!(
            step,
            RedLabelTerrainBlowProcessStep::Completed {
                process_address: final_process,
                iteration: 16,
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4C7,
                    priority: 0xE8,
                }),
                killed_process: RedLabelKilledProcess {
                    killed_process_address: final_process,
                    previous_link_address: loop_process,
                },
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD4, 0xC5, 0xE8, 0x01, 0x01][..])
        );
    }

