        machine
            .memory
            .write_word(process + 0x09, astronaut)
            .expect("set PD2");
        machine
            .memory
            .write_word(process + 0x0B, 0xA11A)
            .expect("set PD4");
        machine
            .memory
            .write_byte(process + 0x0D, 2)
            .expect("set PD6");
        machine
            .memory
            .write_word(0xA11A, astronaut)
            .expect("set TLIST");
        machine
            .memory
            .write_word(0xA103, 0x0100)
            .expect("set LNDYV");
        machine
            .memory
            .write_word(lander + 0x0A, 0x2000)
            .expect("set lander X");
        machine
            .memory
            .write_word(lander + 0x0C, 0x5400)
