    #[test]
    fn lands0_without_targets_converts_lander_to_schizoid_immediately() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "LANDS0");
        let lander = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("LNDP1")
                        .expect("LNDP1 address"),
                    collision_vector_address: red_label_routine_address("LKILL")
                        .expect("LKILL address"),
                    scanner_color: 0x4433,
                },
            )
            .expect("init lander")
            .object_address;
        machine
            .memory
            .write_word(process + 0x07, lander)
            .expect("set PD");
        machine
            .memory
            .write_word(process + 0x0B, 0xA11A)
            .expect("set PD4");
        machine.memory.write_byte(0xA0FA, 0).expect("clear ASTCNT");
        machine.memory.write_byte(0xA112, 1).expect("set LNDCNT");
        machine.memory.write_byte(0xA115, 0).expect("clear SCZCNT");
        machine.memory.write_byte(0xA10A, 0x20).expect("set SZXV");
        machine.memory.write_word(0xA108, 0x0080).expect("set SZYV");
        machine.memory.write_byte(0xA10B, 0x04).expect("set SZSTIM");
        machine
            .memory
            .write_word(0xA0CC, 0x2000)
            .expect("set PLABX");
        machine.memory.write_byte(0xA0C0, 0x60).expect("set PLAYC");
        machine
            .memory
            .write_word(lander + 0x0A, 0x2000)
            .expect("set lander X");
        machine
            .memory
            .write_word(lander + 0x0C, 0x6000)
            .expect("set lander Y");
        machine
            .memory
            .write_byte(lander + 0x14, 1)
            .expect("set OTYP");

        let step = machine
            .red_label_step_lander_orbit_current_process()
            .expect("LANDS0 no target");
        let RedLabelLanderProcessStep::ConvertedToSchizoid {
            process_address,
            object_address,
            active_lander_count,
            active_schizoid_count,
            schizoid,
        } = step
        else {
            panic!("expected lander to schizoid conversion");
        };

        assert_eq!(process_address, process);
        assert_eq!(object_address, lander);
        assert_eq!(active_lander_count, 0);
        assert_eq!(active_schizoid_count, 1);
        assert_eq!(schizoid.process_address, process);
        assert_eq!(schizoid.object_address, lander);
        assert_eq!(
            machine.red_label_ram_range(lander + 0x02..lander + 0x15),
            Some(
                &[
                    0xF8,
                    0xCE,
                    0,
                    0,
                    process.to_be_bytes()[0],
                    process.to_be_bytes()[1],
                    0xEF,
                    0x6D,
                    0x20,
                    0,
                    0x60,
                    0,
                    0x00,
                    0x20,
                    0x00,
                    0x80,
                    0xCC,
                    0x33,
                    0,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x0B),
            Some(
                &[
                    0xF1,
                    0x5E,
                    3,
                    RED_LABEL_SYSTEM_PROCESS_TYPE,
                    0,
                    lander.to_be_bytes()[0],
                    lander.to_be_bytes()[1],
                    4,
                    0,
                ][..]
            )
        );
    }

    #[test]
    fn ufokil_collision_decrements_ufo_count_and_runs_kilp_path() {
        let mut machine = ArcadeMachine::new();
        let (process, object) = setup_kilp_enemy_object(
            &mut machine,
            "UFOP1",
            "UFOKIL",
            0x3333,
            0x4058,
            0x1800,
            0x5800,
        );
        machine.memory.write_byte(0xA119, 1).expect("set UFOCNT");

        let collision = machine
            .red_label_dispatch_object_collision_vector(object)
            .expect("dispatch UFOKIL");
        let RedLabelObjectCollision::UfoKilled(kill) = collision else {
            panic!("expected UFOKIL enemy kill");
        };

        assert_eq!(machine.red_label_ram_range(0xA119..0xA11A), Some(&[0][..]));
        assert_eq!(kill.object_address, object);
        assert_eq!(
            kill.killed_process,
            RedLabelKilledProcess {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            }
        );
        assert_eq!(kill.previous_object_link_address, 0xA065);
        assert_eq!(
            kill.score,
            RedLabelScoreOutcome {
                player_number: 1,
                bonus_awarded: false,
                sound_loaded: None,
            }
        );
        assert_eq!(
            kill.explosion,
            RedLabelExplosionStart {
                object_address: object,
                picture_address: red_label_object_picture_address("UFOP1").unwrap(),
                relative_x: 0x1800,
                slot_address: Some(0x9C00),
                erased_previous_slot: false,
                top_left: Some(0x6058),
                center: Some(0x635A),
            }
        );
        assert_eq!(
            kill.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD4FD,
                priority: 0xD0,
            })
        );
        assert_eq!(machine.snapshot().scores.player_one, 200);
    }

