    #[test]
    fn lkil1_collision_releases_passenger_then_kills_lander() {
        let mut machine = ArcadeMachine::new();
        let (lander_process, lander_object) = setup_kilp_enemy_object(
            &mut machine,
            "LNDP1",
            "LKIL1",
            0x4433,
            0x4862,
            0x1C00,
            0x6200,
        );
        let passenger = machine
            .red_label_init_object_cell(
                lander_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("ASTP1")
                        .expect("ASTP1 address"),
                    collision_vector_address: red_label_routine_address("ASTKIL")
                        .expect("ASTKIL address"),
                    scanner_color: 0x1111,
                },
            )
            .expect("init passenger")
            .object_address;
        machine
            .red_label_activate_object_cell(passenger)
            .expect("activate passenger");
        machine
            .memory
            .write_word(lander_process + 0x09, passenger)
            .expect("set lander PD2");
        machine
            .memory
            .write_word(lander_process + 0x0B, 0xA11A)
            .expect("set lander PD4");
        machine
            .memory
            .write_word(0xA11A, passenger)
            .expect("target slot alive");
        machine
            .memory
            .write_word(passenger + 0x10, 0x0123)
            .expect("set passenger OYV");
        machine.memory.write_byte(0xA112, 1).expect("set LNDCNT");

        let collision = machine
            .red_label_dispatch_object_collision_vector(lander_object)
            .expect("dispatch LKIL1");
        let RedLabelObjectCollision::KidnappingLanderKilled(kill) = collision else {
            panic!("expected LKIL1 kidnapping lander kill");
        };

        assert_eq!(
            kill,
            RedLabelKidnappingLanderKill {
                passenger_release: Some(RedLabelKidnappingPassengerRelease {
                    falling_process: RedLabelCreatedProcess {
                        process_address: 0xAAD4,
                        routine_address: red_label_routine_address("AFALL").expect("AFALL address"),
                        process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                        class: RedLabelProcessClass::Regular,
                    },
                    passenger_object_address: passenger,
                    target_slot_address: 0xA11A,
                    sound_loaded: Some(RedLabelLoadedSoundTable {
                        address: 0xD4E9,
                        priority: 0xD8,
                    }),
                }),
                lander: RedLabelEnemyKill {
                    object_address: lander_object,
                    killed_process: RedLabelKilledProcess {
                        killed_process_address: lander_process,
                        previous_link_address: 0xAAD4,
                    },
                    previous_object_link_address: passenger,
                    score: RedLabelScoreOutcome {
                        player_number: 1,
                        bonus_awarded: false,
                        sound_loaded: None,
                    },
                    explosion: RedLabelExplosionStart {
                        object_address: lander_object,
                        picture_address: red_label_object_picture_address("LNDP1")
                            .expect("LNDP1 address"),
                        relative_x: 0x1C00,
                        slot_address: Some(0x9C00),
                        erased_previous_slot: false,
                        top_left: Some(0x7062),
                        center: Some(0x7266),
                    },
                    sound_loaded: None,
                },
            }
        );
        assert_eq!(machine.red_label_ram_range(0xA112..0xA113), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0xAAD4..0xAAE3),
            Some(
                &[
                    0x00,
                    0x00,
                    0xF2,
                    0x16,
                    0x01,
                    RED_LABEL_SYSTEM_PROCESS_TYPE,
                    0x00,
                    passenger.to_be_bytes()[0],
                    passenger.to_be_bytes()[1],
                    0x00,
                    0x00,
                    0x00,
                    0x00,
                    0x00,
                    0x00,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(passenger + 0x06..passenger + 0x12),
            Some(
                &[
                    0xAA, 0xD4, 0xED, 0x70, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD4, 0xE7, 0xD8, 0x01, 0x01][..])
        );
        assert_eq!(machine.snapshot().scores.player_one, 150);
    }

    #[test]
    fn afall_accelerates_falling_astronaut_and_sleeps_above_ground() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "AFALL");
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("ASTP1")
                        .expect("ASTP1 address"),
                    collision_vector_address: red_label_routine_address("ASTKIL")
                        .expect("ASTKIL address"),
                    scanner_color: 0x1111,
                },
            )
            .expect("init falling astronaut")
            .object_address;
        machine
            .red_label_activate_object_cell(object)
            .expect("activate falling astronaut");
        machine
            .memory
            .write_word(process + 0x07, object)
            .expect("set AFALL PD");
        machine
            .memory
            .write_word(object + 0x0A, 0x1000)
            .expect("set OX16");
        machine
            .memory
            .write_word(object + 0x0C, 0x5000)
            .expect("set OY16");
        machine
            .memory
            .write_word(object + 0x10, 0x0010)
            .expect("set OYV");
        machine
            .memory
            .write_byte(0xB340, 0x60)
            .expect("set ALTTBL altitude");

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("AFALL").expect("AFALL address"),
            )
            .expect("dispatch AFALL");
        let RedLabelProcessDispatch::FallingAstronaut(step) = dispatch else {
            panic!("expected AFALL dispatch");
        };

        assert_eq!(
            step,
            RedLabelFallingAstronautStep::FallingSleeping {
                process_address: process,
                object_address: object,
                y_velocity: 0x0018,
                altitude: 0x60,
                wakeup_address: red_label_routine_address("AFALL").expect("AFALL address"),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(object + 0x10..object + 0x12),
            Some(&[0x00, 0x18][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xF2, 0x16, 0x04][..])
        );
    }

