    #[test]
    fn sound_sequence_runs_thrust_start_and_stop_gate() {
        let mut machine = ArcadeMachine::new();
        machine.memory.write_byte(0xA07B, 0x02).expect("set PIA21");
        machine.memory.write_byte(0xA0BA, 0).expect("clear STATUS");

        let started = machine
            .red_label_step_sound_sequence()
            .expect("start thrust sound");

        assert_eq!(
            started,
            RedLabelSoundSequenceStep {
                source: RedLabelSoundSequenceSource::ThrustStarted,
                timer_before: 0,
                timer_after: 0,
                repeat_before: 0,
                repeat_after: 0,
                table_pointer_before: 0,
                table_pointer_after: 0,
                priority_after: 0,
                thrust_flag_before: 0,
                thrust_flag_after: 0x16,
                sound_number: Some(0x16),
                sound_output: Some(red_label_sound_output(0x16)),
                command: Some(SoundCommand::from_main_board_pia_port_b(0x29)),
            }
        );

        machine.memory.write_byte(0xA07B, 0).expect("clear PIA21");
        let stopped = machine
            .red_label_step_sound_sequence()
            .expect("stop thrust sound");

        assert_eq!(
            stopped,
            RedLabelSoundSequenceStep {
                source: RedLabelSoundSequenceSource::ThrustStopped,
                timer_before: 0,
                timer_after: 0,
                repeat_before: 0,
                repeat_after: 0,
                table_pointer_before: 0,
                table_pointer_after: 0,
                priority_after: 0,
                thrust_flag_before: 0x16,
                thrust_flag_after: 0,
                sound_number: Some(0x0F),
                sound_output: Some(red_label_sound_output(0x0F)),
                command: Some(SoundCommand::from_main_board_pia_port_b(0x30)),
            }
        );
    }

    #[test]
    fn object_picture_parser_preserves_short_form_descriptor_shape() {
        let short_form = parse_object_pictures(concat!(
            "label\taddress\twidth\theight\tprimary_image\talternate_image\t",
            "output_routine\terase_routine\tsource\n",
            "LASP1\t0xF96F\t8\t1\t0xF973\t\t\t\tsource\n",
        ))
        .expect("short form object picture");

        assert_eq!(short_form[0].alternate_image, None);
        assert_eq!(short_form[0].output_routine, None);
        assert_eq!(short_form[0].erase_routine, None);

        let error = parse_object_pictures(concat!(
            "label\taddress\twidth\theight\tprimary_image\talternate_image\t",
            "output_routine\terase_routine\tsource\n",
            "BROKEN\t0xF96F\t8\t1\t0xF973\t0xF973\t\t\tsource\n",
        ))
        .expect_err("partial optional descriptor");

        assert!(error.contains("all optional descriptor words or none"));
    }

