    #[test]
    fn hyperspace_fixture_covers_guard_rematerialization_safe_tail_and_death_risk() {
        let mut guarded = ArcadeMachine::new();
        let guarded_process = schedule_hyperspace_process(&mut guarded);
        guarded
            .memory
            .write_byte(0xA0BA, 0x08)
            .expect("set blocking STATUS");

        let guarded_entry = guarded
            .red_label_start_hyperspace_current_process()
            .expect("guarded HYPER entry");

        assert_eq!(
            guarded_entry,
            RedLabelHyperspace::Suppressed(RedLabelKilledProcess {
                killed_process_address: guarded_process,
                previous_link_address: 0xA05F,
            })
        );
        assert_eq!(
            guarded.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x08][..])
        );

        let mut safe = ArcadeMachine::new();
        let safe_process = schedule_hyperspace_process(&mut safe);
        safe.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        safe.memory.write_byte(0xA0E0, 0x35).expect("set HSEED");
        safe.memory.write_byte(0xA0E1, 0xC0).expect("set LSEED");
        safe.memory.write_word(0xA0C5, 0x8034).expect("set PLAY16");
        safe.memory.write_byte(0xA0FA, 1).expect("set ASTCNT");

        let rematerializing = safe
            .red_label_continue_hyperspace_current_process()
            .expect("safe HYP02");
        assert!(matches!(
            rematerializing,
            RedLabelHyperspace::RematerializingSleeping {
                process_address,
                seed_word: 0x1235,
                player_x16: 0x2000,
                player_y16: 0x4434,
                player_upper_left: 0x2044,
                player_direction: 0x0300,
                phony_object_address: 0xA23C,
                phony_picture_address: 0xF9C1,
                wakeup_address: 0xE9AC,
                ..
            } if process_address == safe_process
        ));
        assert_eq!(
            safe.red_label_ram_range(0xA0BA..0xA0CD),
            Some(
                &[
                    0x50, 0x03, 0x00, 0x00, 0x00, 0x00, 0x00, 0x20, 0x44, 0x20, 0x00, 0x44, 0x34,
                    0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
                ][..],
            )
        );

        let safe_tail = safe
            .red_label_finish_hyperspace_current_process()
            .expect("safe HYP2");
        assert_eq!(
            safe_tail,
            RedLabelHyperspace::Completed {
                process_address: safe_process,
                phony_object_address: 0xA23C,
                previous_object_link_address: 0xA065,
                status: 0x00,
                lseed: 0xC0,
                killed_process: RedLabelKilledProcess {
                    killed_process_address: safe_process,
                    previous_link_address: 0xA05F,
                },
            }
        );
        assert_eq!(safe.red_label_ram_range(0xA0BA..0xA0BB), Some(&[0][..]));

        let mut risky = ArcadeMachine::new();
        let risky_process = schedule_hyperspace_process(&mut risky);
        risky.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        risky.memory.write_byte(0xA0E0, 0x34).expect("set HSEED");
        risky.memory.write_byte(0xA0E1, 0xC1).expect("set LSEED");
        risky
            .red_label_continue_hyperspace_current_process()
            .expect("risky HYP02");

        let risky_tail = risky
            .red_label_finish_hyperspace_current_process()
            .expect("risky HYP2");

        assert_eq!(
            risky_tail,
            RedLabelHyperspace::DeathRisk {
                process_address: risky_process,
                phony_object_address: 0xA23C,
                previous_object_link_address: 0xA065,
                status: 0x02,
                lseed: 0xC1,
                plend_address: 0xDA46,
            }
        );
        assert_eq!(
            risky.red_label_ram_range(0xA05F..0xA063),
            Some(&[0xAA, 0xC5, 0xAA, 0xD4][..])
        );
    }

    #[test]
    fn player_death_entry_saves_state_builds_mono_picture_and_sleeps() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_player_death_process(&mut machine);
        let player_picture = red_label_object_picture_address("PLAPIC").expect("PLAPIC address");
        machine.memory.write_word(0xA020, 0x3456).expect("set BGL");
        machine.memory.write_byte(0xA0FA, 5).expect("set ASTCNT");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine
            .memory
            .write_word(0xA0BB, 0x0300)
            .expect("set NPLAD");
        machine
            .memory
            .write_word(0xA0BF, 0x4050)
            .expect("set PLAXC");
        machine
            .memory
            .write_word(0xA0C1, 0x5060)
            .expect("set NPLAXC");
        write_object_footprint(&mut machine, 0x4050, player_picture, 0xCC);
        write_object_footprint(&mut machine, 0x5060, player_picture, 0xDD);
        write_ram_bytes(&mut machine, 0xA1CC, &[0xEE; 0x33]);
        write_ram_bytes(
            &mut machine,
            0xA0FB,
            &[
                1, 2, 3, 4, 5, 0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19, 0x1A,
                0x1B, 0x1C, 0x1D, 0x1E, 0x1F, 0x20, 0x21,
            ],
        );
        write_ram_bytes(
            &mut machine,
            0xA112,
            &[10, 20, 30, 40, 50, 0x60, 0x61, 0x62],
        );

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("PLEND").expect("PLEND address"),
            )
            .expect("dispatch PLEND");

        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::PlayerDeath(RedLabelPlayerDeath::StartedSleeping {
                process_address: process,
                status: 0x58,
                background_left: 0x3456,
                player_screen_address: 0x4050,
                next_player_screen_address: 0x5060,
                player_picture_address: 0xF9C1,
                glow_table_address: 0xDB47,
                mono_picture_address: 0xAFDD,
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4B5,
                    priority: 0xF0,
                }),
                wakeup_address: 0xDA8C,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA020..0xA024),
            Some(&[0x34, 0x56, 0x34, 0x56][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x58][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD4, 0xB3, 0xF0, 0x01, 0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x0D),
            Some(
                &[
                    0xDA, 0x8C, 0x02, 0x00, 0x00, 0xDB, 0x47, 0x00, 0x00, 0xAF, 0xDD
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1CC..0xA1E4),
            Some(
                &[
                    0x05, 0x0B, 0x16, 0x21, 0x2C, 0x37, 0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16,
                    0x17, 0x18, 0x19, 0x1A, 0x1B, 0x1C, 0x1D, 0x1E, 0x1F, 0x20, 0x21,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1E4..0xA1FF),
            Some(&[0; 0x1B][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAFDD..0xAFE7),
            Some(&[0x08, 0x06, 0xAF, 0xE7, 0xB0, 0x17, 0xD2, 0x8E, 0xD2, 0xDF][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAFE7..0xAFED),
            Some(&[0x00, 0x0B, 0xBB, 0x0B, 0xBB, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA036..0xA037),
            Some(&[0x02][..])
        );
        assert_object_footprint_cleared(&machine, 0x4050, player_picture);
        assert_object_footprint_cleared(&machine, 0x5060, player_picture);
    }

