    #[test]
    fn player_death_glow_loop_draws_then_blanks_until_final_flash() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_player_death_process(&mut machine);
        let player_picture = red_label_object_picture_address("PLAPIC").expect("PLAPIC address");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine
            .memory
            .write_word(0xA0BB, 0x0300)
            .expect("set NPLAD");
        machine
            .memory
            .write_word(0xA0C1, 0x5060)
            .expect("set NPLAXC");
        machine
            .red_label_start_player_death_current_process()
            .expect("PLEND entry");

        let first_glow = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("PDTH2").expect("PDTH2 address"),
            )
            .expect("dispatch PDTH2");

        assert_eq!(
            first_glow,
            RedLabelProcessDispatch::PlayerDeath(RedLabelPlayerDeath::GlowWrittenSleeping {
                process_address: process,
                player_screen_address: 0x5060,
                mono_picture_address: 0xAFDD,
                glow_value: 0x07,
                next_glow_table_address: 0xDB48,
                wakeup_address: 0xDA7C,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0x5060..0x5066),
            Some(&[0x00, 0x0B, 0xBB, 0x0B, 0xBB, 0x00][..])
        );
        let mut expected_glow_pcram = CRTAB_BYTES;
        expected_glow_pcram[11] = 0x07;
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA032),
            Some(&expected_glow_pcram[..12])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x09),
            Some(&[0xDA, 0x7C, 0x02, 0x00, 0x00, 0xDB, 0x48][..])
        );

        let blank = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("PDTHL").expect("PDTHL address"),
            )
            .expect("dispatch PDTHL");

        assert_eq!(
            blank,
            RedLabelProcessDispatch::PlayerDeath(RedLabelPlayerDeath::GlowBlankedSleeping {
                process_address: process,
                player_screen_address: 0x5060,
                mono_picture_address: 0xAFDD,
                wakeup_address: 0xDA8C,
            })
        );
        assert_object_footprint_cleared(&machine, 0x5060, player_picture);
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xDA, 0x8C, 0x02][..])
        );

        machine
            .memory
            .write_word(process + 0x07, 0xDB4F)
            .expect("point at PXCTB terminator");
        let final_flash = machine
            .red_label_continue_player_death_glow_current_process()
            .expect("final PDTH2 branch");

        assert_eq!(
            final_flash,
            RedLabelPlayerDeath::FinalFlashSleeping {
                process_address: process,
                player_screen_address: 0x5060,
                mono_picture_address: 0xAFDD,
                status: 0x7F,
                pseudo_color: 0xFF,
                wakeup_address: 0xDAB8,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0xFF][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x7F][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xDA, 0xB8, 0x02][..])
        );
    }

    #[test]
    fn player_death_tail_starts_bank7_explosion_and_kills_non_coin_processes() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_player_death_process(&mut machine);
        let extra_process = machine
            .red_label_make_process(
                red_label_routine_address("REV").expect("REV address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make extra process")
            .process_address;
        let coin_process = machine
            .red_label_make_process(
                red_label_routine_address("REV").expect("REV address"),
                RED_LABEL_COIN_PROCESS_TYPE,
            )
            .expect("make coin process")
            .process_address;
        machine
            .memory
            .write_word(0xA0C1, 0x5060)
            .expect("set NPLAXC");
        machine.memory.write_byte(0xA026, 0xFF).expect("set PCRAM");

        let death = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("PDTH5").expect("PDTH5 address"),
            )
            .expect("dispatch PDTH5");

        assert_eq!(
            death,
            RedLabelProcessDispatch::PlayerDeath(RedLabelPlayerDeath::ExplosionStartedSleeping {
                process_address: process,
                player_center: 0x5463,
                return_address: 0xDAC9,
                wakeup_address: 0xC649,
                killed_processes: 1,
            })
        );
        assert_eq!(machine.red_label_ram_range(0xA026..0xA027), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0xA036..0xA037), Some(&[7][..]));
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x0B),
            Some(&[0xC6, 0x49, 0x01, 0x00, 0x00, 0, 0, 0xDA, 0xC9][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA001..0xA004),
            Some(&[56, 0xC6, 0xAB][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xB300..0xB306),
            Some(&[0, 0, 0x54, 0, 0x63, 0][..])
        );
        assert!(
            machine.red_label_kill_process(extra_process).is_err(),
            "GNCIDE should already have returned the extra process to FREE"
        );
        assert!(
            machine.red_label_kill_process(coin_process).is_ok(),
            "GNCIDE must leave coin processes active"
        );
    }

    #[test]
    fn player_explosion_frame_uses_pxcol_and_resleeps_to_px1a() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_player_death_process(&mut machine);
        machine
            .memory
            .write_word(0xA0C1, 0x5060)
            .expect("set NPLAXC");
        machine
            .red_label_start_player_death_tail_current_process()
            .expect("PDTH5 entry");

        let frame = machine
            .red_label_continue_player_explosion_current_process()
            .expect("PX1A frame");

        let RedLabelPlayerDeath::ExplosionFrameSleeping {
            process_address,
            color,
            color_counter,
            color_pointer,
            live_pieces,
            wakeup_address,
        } = frame
        else {
            panic!("expected explosion frame sleep");
        };
        assert_eq!(process_address, process);
        assert_eq!(color, 0xFF);
        assert_eq!(color_counter, 55);
        assert_eq!(color_pointer, 0xC6AB);
        assert!(live_pieces > 0);
        assert_eq!(wakeup_address, 0xC649);
        let mut expected_explosion_pcram = CRTAB_BYTES;
        expected_explosion_pcram[11] = 0xFF;
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA032),
            Some(&expected_explosion_pcram[..12])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xC6, 0x49, 0x01][..])
        );
    }

