    #[test]
    fn smart_bomb_world_fixture_kills_enemies_and_preserves_non_enemy_objects() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let smart_bomb_process = schedule_smart_bomb_process(&mut machine);
        let skipped_process = machine
            .red_label_make_process(
                red_label_routine_address("NOKILL").expect("NOKILL address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make skipped owner process")
            .process_address;
        let skipped_object = machine
            .red_label_init_object_cell(
                skipped_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SWPIC1")
                        .expect("SWPIC1 address"),
                    collision_vector_address: red_label_routine_address("NOKILL")
                        .expect("NOKILL address"),
                    scanner_color: 0x1212,
                },
            )
            .expect("init skipped object")
            .object_address;
        machine
            .red_label_activate_object_cell(skipped_object)
            .expect("activate skipped object");
        machine
            .memory
            .write_word(skipped_object + 0x04, 0x3040)
            .expect("set skipped OBJX/OBJY");
        machine
            .memory
            .write_byte(skipped_object + 0x14, 0x02)
            .expect("mark skipped object as non-enemy type");

        let enemy_process = machine
            .red_label_make_process(
                red_label_routine_address("MSWM").expect("MSWM address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make enemy owner process")
            .process_address;
        let enemy_object = machine
            .red_label_init_object_cell(
                enemy_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("SWPIC1")
                        .expect("SWPIC1 address"),
                    collision_vector_address: red_label_routine_address("MSWKIL")
                        .expect("MSWKIL address"),
                    scanner_color: 0x2424,
                },
            )
            .expect("init enemy object")
            .object_address;
        machine
            .red_label_activate_object_cell(enemy_object)
            .expect("activate enemy object");
        machine
            .memory
            .write_byte(0xA116, 1)
            .expect("set active swarmer count");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(enemy_object + 0x04, 0x5060)
            .expect("set enemy OBJX/OBJY");
        machine
            .memory
            .write_word(enemy_object + 0x0A, 0x2040)
            .expect("set enemy OX16");
        machine
            .memory
            .write_word(enemy_object + 0x0C, 0x6200)
            .expect("set enemy OY16");
        write_ram_bytes(&mut machine, 0x5060, &[0xFF, 0xFF, 0xFF]);
        write_ram_bytes(&mut machine, 0x5160, &[0xFF, 0xFF, 0xFF]);

        let smart_bomb = machine
            .red_label_start_smart_bomb_current_player()
            .expect("start smart bomb")
            .expect("smart bomb started");

        assert_eq!(smart_bomb.player_number, 1);
        assert_eq!(smart_bomb.remaining_smart_bombs, 2);
        assert_eq!(smart_bomb.collisions.len(), 1);
        let RedLabelObjectCollision::MiniSwarmerKilled(kill) = &smart_bomb.collisions[0] else {
            panic!("expected smart bomb to kill mini swarmer");
        };
        assert_eq!(kill.object_address, enemy_object);
        assert_eq!(kill.killed_process.killed_process_address, enemy_process);
        assert_eq!(kill.active_swarmer_count, 0);
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&skipped_object.to_be_bytes()[..])
        );
        assert_eq!(
            machine.red_label_ram_range(skipped_object + 0x04..skipped_object + 0x06),
            Some(&[0x30, 0x40][..])
        );
        assert_eq!(
            machine.red_label_ram_range(skipped_object + 0x14..skipped_object + 0x15),
            Some(&[0x02][..])
        );
        assert_eq!(machine.red_label_ram_range(0xA116..0xA117), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0x5060..0x5063),
            Some(&[0, 0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x5160..0x5163),
            Some(&[0, 0, 0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(smart_bomb_process + 0x02..smart_bomb_process + 0x08),
            Some(&[0xE9, 0x00, 0x02, 0x00, 0x00, 0x04][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09A..0xA09B),
            Some(&[0x01][..])
        );
    }

    #[test]
    fn smart_bomb_flash_tail_counts_down_and_enters_debounce_sleep() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let process = schedule_smart_bomb_process(&mut machine);
        machine.memory.write_byte(0xA026, 0x55).expect("seed PCRAM");
        machine
            .red_label_start_smart_bomb_current_player()
            .expect("start smart bomb")
            .expect("smart bomb started");

        let first = machine
            .red_label_continue_smart_bomb_flash_tail()
            .expect("first flash tail");
        assert_eq!(
            first,
            RedLabelSmartBombTail::FlashSleeping {
                remaining_flash_count: 3,
                wakeup_address: 0xE900,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0x55][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x08),
            Some(&[0xE9, 0x00, 0x02, 0x00, 0x00, 0x03][..])
        );

        let second = machine
            .red_label_continue_smart_bomb_flash_tail()
            .expect("second flash tail");
        assert_eq!(
            second,
            RedLabelSmartBombTail::FlashSleeping {
                remaining_flash_count: 2,
                wakeup_address: 0xE900,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0xAA][..])
        );

        let third = machine
            .red_label_continue_smart_bomb_flash_tail()
            .expect("third flash tail");
        assert_eq!(
            third,
            RedLabelSmartBombTail::FlashSleeping {
                remaining_flash_count: 1,
                wakeup_address: 0xE900,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0x55][..])
        );

        let fourth = machine
            .red_label_continue_smart_bomb_flash_tail()
            .expect("fourth flash tail");
        assert_eq!(
            fourth,
            RedLabelSmartBombTail::DebounceSleeping {
                wakeup_address: 0xE90C,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0x55][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x08),
            Some(&[0xE9, 0x0C, 0x0A, 0x00, 0x00, 0x00][..])
        );
    }

    #[test]
    fn translated_process_dispatch_runs_smart_bomb_path_from_scheduler() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SBOMB").expect("SBOMB address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make SBOMB process")
            .process_address;
        machine.memory.write_byte(0xA026, 0x55).expect("seed PCRAM");

        let started = machine
            .step_red_label_translated_process()
            .expect("dispatch SBOMB")
            .expect("scheduled SBOMB");
        assert_eq!(
            started,
            RedLabelProcessDispatch::SmartBombStarted(Some(RedLabelSmartBomb {
                player_number: 1,
                remaining_smart_bombs: 2,
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4D2,
                    priority: 0xE8,
                }),
                collisions: Vec::new(),
                flash_count: 4,
            }))
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x08),
            Some(&[0xE9, 0x00, 0x02, 0x00, 0x00, 0x04][..])
        );

        assert_eq!(
            machine
                .step_red_label_translated_process()
                .expect("sleep tick"),
            None
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x04..process + 0x05),
            Some(&[0x01][..])
        );

        let flash = machine
            .step_red_label_translated_process()
            .expect("dispatch SBMBX1")
            .expect("scheduled SBMBX1");
        assert_eq!(
            flash,
            RedLabelProcessDispatch::SmartBombTail(RedLabelSmartBombTail::FlashSleeping {
                remaining_flash_count: 3,
                wakeup_address: 0xE900,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x08),
            Some(&[0xE9, 0x00, 0x02, 0x00, 0x00, 0x03][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA026..0xA027),
            Some(&[0x55][..])
        );
    }

    #[test]
    fn translated_process_dispatch_suicides_guarded_smart_bomb_without_clearing_flag() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SBOMB").expect("SBOMB address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make guarded SBOMB process")
            .process_address;
        machine
            .memory
            .write_byte(0xA09A, 0x01)
            .expect("set active SBFLG");

        let dispatch = machine
            .step_red_label_translated_process()
            .expect("dispatch guarded SBOMB")
            .expect("scheduled guarded SBOMB");

        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SmartBombTail(RedLabelSmartBombTail::Completed {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09A..0xA09B),
            Some(&[0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1CB..0xA1CC),
            Some(&[0x03][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&[0xAA, 0xC5][..])
        );
    }

    #[test]
    fn translated_process_dispatch_executes_generic_sucide_tails() {
        for label in ["SUCIDE", "HYPX"] {
            let mut machine = ArcadeMachine::new();
            let process = machine
                .red_label_make_process(
                    red_label_routine_address(label).expect("routine address"),
                    RED_LABEL_SYSTEM_PROCESS_TYPE,
                )
                .expect("make process")
                .process_address;

            let dispatch = machine
                .step_red_label_translated_process()
                .expect("dispatch routine")
                .expect("scheduled routine");

            assert_eq!(
                dispatch,
                RedLabelProcessDispatch::Suicide(RedLabelKilledProcess {
                    killed_process_address: process,
                    previous_link_address: 0xA05F,
                }),
                "{label} should use the generic process cleanup tail"
            );
            assert_eq!(
                machine.red_label_ram_range(0xA05F..0xA061),
                Some(&[0x00, 0x00][..]),
                "{label} should unlink the active process"
            );
            assert_eq!(
                machine.red_label_ram_range(0xA061..0xA063),
                Some(&process.to_be_bytes()[..]),
                "{label} should return the cell to FREE"
            );
            assert_eq!(
                machine.red_label_ram_range(0xA063..0xA065),
                Some(&[0xA0, 0x5F][..]),
                "{label} should rewind CRPROC to the previous link cell"
            );
            assert_eq!(
                machine.red_label_ram_range(process..process + 2),
                Some(&[0xAA, 0xD4][..]),
                "{label} should preserve the old FREE head in PLINK"
            );
        }
    }

    #[test]
    fn translated_process_dispatch_rejects_untranslated_routine_address() {
        let mut machine = ArcadeMachine::new();
        machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make untranslated process");

        let error = machine
            .step_red_label_translated_process()
            .expect_err("untranslated process routine");

        assert!(error.contains("0x1234"));
    }

    #[test]
    fn smart_bomb_debounce_tail_repeats_until_switch_released_then_suicides() {
        let mut machine = ArcadeMachine::new();
        start_one_player_game_for_test(&mut machine);
        let process = schedule_smart_bomb_process(&mut machine);
        machine
            .red_label_start_smart_bomb_current_player()
            .expect("start smart bomb")
            .expect("smart bomb started");

        machine
            .memory
            .write_byte(0xA07B, 0x04)
            .expect("hold smart-bomb switch");
        let pressed = machine
            .red_label_continue_smart_bomb_debounce_tail()
            .expect("pressed debounce tail");
        assert_eq!(
            pressed,
            RedLabelSmartBombTail::DebounceSleeping {
                wakeup_address: 0xE90C,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE9, 0x0C, 0x0A][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09A..0xA09B),
            Some(&[0x01][..])
        );

        machine
            .memory
            .write_byte(0xA07B, 0x00)
            .expect("release smart-bomb switch");
        let released = machine
            .red_label_continue_smart_bomb_debounce_tail()
            .expect("released debounce tail");
        assert_eq!(
            released,
            RedLabelSmartBombTail::ReleaseSleeping {
                wakeup_address: 0xE91A,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE9, 0x1A, 0x0A][..])
        );

        let finished = machine
            .red_label_finish_smart_bomb_tail()
            .expect("finish smart bomb tail");
        assert_eq!(
            finished,
            RedLabelSmartBombTail::Completed {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09A..0xA09B),
            Some(&[0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&[0xAA, 0xC5][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process..process + 2),
            Some(&[0xAA, 0xD4][..])
        );
    }

