    #[test]
    fn get_shell_cell_rejects_source_conditions_without_allocating() {
        let mut machine = ArcadeMachine::new();
        let source = machine
            .red_label_get_object_cell()
            .expect("get firing object cell");
        machine.memory.write_word(0xA020, 0x1000).expect("set BGL");
        machine
            .memory
            .write_word(source + 0x0A, 0x1100)
            .expect("set source OX16");
        machine
            .memory
            .write_word(source + 0x0C, 0x5001)
            .expect("set source OY16");
        machine
            .memory
            .write_byte(0xA099, 20)
            .expect("set BMBCNT limit");
        let descriptor = RedLabelShellDescriptor {
            output_routine_address: 0x1111,
            picture_address: 0x2222,
            kill_routine_address: 0x3333,
        };

        let saturated = machine
            .red_label_get_shell_cell(source, 0x4444, descriptor)
            .expect("saturated shell check");

        assert_eq!(saturated, None);
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA06D..0xA06F),
            Some(&[0, 0][..])
        );

        machine.memory.write_byte(0xA099, 0).expect("reset BMBCNT");
        machine
            .memory
            .write_word(source + 0x0A, 0x3580)
            .expect("set offscreen source OX16");
        let offscreen = machine
            .red_label_get_shell_cell(source, 0x4444, descriptor)
            .expect("offscreen shell check");

        assert_eq!(offscreen, None);
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x53][..])
        );

        machine
            .memory
            .write_word(source + 0x0A, 0x1100)
            .expect("reset source OX16");
        machine
            .memory
            .write_word(source + 0x0C, 0x2A01)
            .expect("set source below minimum Y");
        let too_high = machine
            .red_label_get_shell_cell(source, 0x4444, descriptor)
            .expect("minimum-y shell check");

        assert_eq!(too_high, None);
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x53][..])
        );
    }

